############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "contextForm.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
