############################################################ # PG Setup Code ############################################################ @ORCCA_variables = grep {!/[eoEOU]/} ('a' .. 'z', 'A' .. 'Z'); $var = list_random(@ORCCA_variables); $scale = random(2,9); $scaleWord = numberWord($scale); $c = $scale**2; Context("Form")->variables->are($var => 'Real'); $answer = Formula("$c $var^3");
############################################################ # Body ############################################################
BEGIN_PGML If a square has side of length [`[$var]\text{,}`] its area is [`[$var]^2\text{.}`] If we grew the side lengths to make them [$scaleWord] times as long, the area would become [`([$scale][$var])^2\text{.}`] Simplify this expression using the product-to-power rule.
[_]{$answer}{10}
END_PGML
